<?php require_once __DIR__.'/../app/rss.php'; $msg=''; if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf(); try{ if(isset($_POST['delete'])) db()->prepare('DELETE FROM feeds WHERE id=?')->execute([$_POST['delete']]); elseif(isset($_POST['order'])){foreach(explode(',',$_POST['order']) as $i=>$id) db()->prepare('UPDATE feeds SET sort_order=? WHERE id=?')->execute([$i,(int)$id]);} else { $p=test_feed($_POST['feed_url']); if(isset($_POST['id'])&&$_POST['id']) db()->prepare('UPDATE feeds SET site_name=?,feed_url=?,memo=?,feed_type=?,updated_at=NOW() WHERE id=?')->execute([$_POST['site_name'],$_POST['feed_url'],$_POST['memo'],$p['type'],$_POST['id']]); else db()->prepare('INSERT INTO feeds(site_name,feed_url,memo,sort_order,feed_type,created_at,updated_at) VALUES(?,?,?,?,?,NOW(),NOW())')->execute([$_POST['site_name'],$_POST['feed_url'],$_POST['memo'],(int)db()->query('SELECT COALESCE(MAX(sort_order),0)+1 FROM feeds')->fetchColumn(),$p['type']]); $msg='テスト成功: '.$p['type'].' / '.count($p['items']).'件 / 画像'.($p['has_images']?'あり':'なし').' / '.implode('、',array_map(fn($i)=>$i['title'],array_slice($p['items'],0,3))); }}catch(Throwable $e){$msg='エラー: '.$e->getMessage();}} admin_header('RSS管理'); if($msg)echo'<p class=notice>'.e($msg).'</p>'; $edit=null; if(isset($_GET['edit'])){ $es=db()->prepare('SELECT * FROM feeds WHERE id=?'); $es->execute([$_GET['edit']]); $edit=$es->fetch(); } echo'<form method=post><input type=hidden name=csrf value='.csrf_token().'><input type=hidden name=id value="'.e($edit['id']??'').'"><input name=site_name placeholder=サイト名 value="'.e($edit['site_name']??'').'" required><input name=feed_url placeholder="RSS URL" value="'.e($edit['feed_url']??'').'" required><textarea name=memo placeholder=メモ>'.e($edit['memo']??'').'</textarea><button>'.($edit?'更新・テスト取得':'登録・テスト取得').'</button></form><form><input name=q placeholder=検索 value="'.e($_GET['q']??'').'"></form>'; $q='%'.($_GET['q']??'').'%'; $page=max(1,(int)($_GET['page']??1)); $st=db()->prepare('SELECT * FROM feeds WHERE site_name LIKE ? OR feed_url LIKE ? ORDER BY sort_order,id LIMIT 20 OFFSET '.(($page-1)*20)); $st->execute([$q,$q]); echo'<table><tr><th>順</th><th>サイト名</th><th>RSS URL</th><th>メモ</th><th>最終取得</th><th>結果</th><th>エラー</th><th>操作</th></tr>'; foreach($st as $r){echo'<tr draggable=true data-id='.$r['id'].'><td>'.e($r['sort_order']).'</td><td>'.e($r['site_name']).'</td><td>'.e($r['feed_url']).'</td><td>'.e($r['memo']).'</td><td>'.e($r['last_fetched_at']).'</td><td>'.e($r['last_result']).'</td><td>'.e($r['last_error']).'</td><td><a class=button href=?edit='.$r['id'].'>編集</a> <form method=post style="display:inline"><input type=hidden name=csrf value='.csrf_token().'><button class=danger name=delete value='.$r['id'].'>削除</button></form></td></tr>'; } echo'</table><form id=orderForm method=post><input type=hidden name=csrf value='.csrf_token().'><input type=hidden name=order id=order></form><p class=muted>行をドラッグ＆ドロップすると並び順と取得順を保存します。1ページ20件。</p><script>let drag;document.querySelectorAll("tr[draggable]").forEach(r=>{r.ondragstart=()=>drag=r;r.ondragover=e=>e.preventDefault();r.ondrop=()=>{if(drag&&drag!==r){r.parentNode.insertBefore(drag,r);document.getElementById("order").value=[...document.querySelectorAll("tr[data-id]")].map(x=>x.dataset.id).join(",");document.getElementById("orderForm").submit();}}});</script>'; admin_footer();
